function loadWordListPackage() {
  try {
    const text = fs.readFileSync(wordListPath, "utf8");
    return text
      .split(/\r?\n/)
      .map((word) => word.trim().toLowerCase())
      .filter((word) => /^[a-z]{2,20}$/.test(word));
  } catch (error) {
    console.warn("Wordfront: word-list package unavailable, using fallback dictionary.", error.message);
    return [];
  }
}

export const WORDS = Array.from(new Set([...FALLBACK_WORDS, ...loadWordListPackage()]));
export const WORD_SET = new Set(WORDS.map((w) => w.toLowerCase()));

export function isDictionaryWord(rawWord) {
  const word = String(rawWord || "").trim().toLowerCase();
  if (!/^[a-z]{2,20}$/.test(word)) return false;
  return WORD_SET.has(word);
}
